];

import { AgeResult, ClassConfig } from './types';
import { CLASSES } from './constants';

export const calculateAge = (dob: Date, targetDate: Date): { years: number; months: number; days: number } => {
  let years = targetDate.getFullYear() - dob.getFullYear();
  let months = targetDate.getMonth() - dob.getMonth();
  let days = targetDate.getDate() - dob.getDate();

  if (days < 0) {
    months--;
    const lastMonth = new Date(targetDate.getFullYear(), targetDate.getMonth(), 0);
    days += lastMonth.getDate();
  }

  if (months < 0) {
    years--;
    months += 12;
  }

  return { years, months, days };
};

export const validateAge = (age: { years: number; months: number; days: number }, classConfig: ClassConfig): AgeResult => {
  const { years, months } = age;
  const totalYearsAsFloat = years + months / 12;

  if (totalYearsAsFloat >= classConfig.minAge && totalYearsAsFloat < classConfig.maxAge) {
    return {
      ...age,
      isValid: true,
      status: 'perfect',
      message: 'Age is valid for selected class',
      suggestion: 'This age is perfect for the selected class'
    };
  } else if (totalYearsAsFloat < classConfig.minAge) {
    // Find best class for this age
    const bestClass = CLASSES.find(c => totalYearsAsFloat >= c.minAge && totalYearsAsFloat < c.maxAge);
    return {
      ...age,
      isValid: false,
      status: 'under-age',
      message: 'Age does NOT meet board criteria',
      suggestion: `This student is under-age for this class. Suggested age: ${classConfig.minAge} Years 0 Months. ${bestClass ? `Best suitable class: ${bestClass.name}` : ''}`
    };
  } else {
    // Over-age
    const bestClass = [...CLASSES].reverse().find(c => totalYearsAsFloat >= c.minAge);
    return {
      ...age,
      isValid: false,
      status: 'over-age',
      message: 'Age does NOT meet board criteria',
      suggestion: `This student is over-age. ${bestClass ? `Best suitable class: ${bestClass.name}` : ''}`
    };
  }
};

export const isValidDate = (day: number, month: number, year: number): boolean => {
  const date = new Date(year, month - 1, day);
  return date.getFullYear() === year && date.getMonth() === month - 1 && date.getDate() === day;
};

